def process_results(doc: dict, results: List[str]) -> Dict[str, int]:
    candidates = results[0]

    try:
        answer = ground_truth_boxed_answer(candidates)
    except:
        answer = get_generated_answer(candidates)

    if is_equiv(answer, doc["answer"]):
        retval = 1
    else:
        retval = 0

    results = {
        "exact_match": retval,
    }

    return results
